            for rx, ry in resources[1:]:
                dr = dist(nx, ny, rx, ry)
                if dr < dres:
                    dres = dr
        dop = dist(nx, ny, ox, oy)
        val = -dres
        if dop <= 2:
            val += dop * 4
        else:
            val += dop
        if bestv is None or val > bestv:
            bestv = val
            best = [dx, dy]

    if best is None:
        for dx, dy in moves:
            nx, ny = sx + dx, sy + dy
            if ok(nx, ny):
                return [dx, dy]
        return [0, 0]
    return best
